class Solution:
    def findKthPositive(self, arr, k):
        lo, hi = 0, len(arr)
        while lo < hi:
            mid = (lo + hi) // 2
            missing = arr[mid] - (mid + 1)
            if missing < k:
                lo = mid + 1
            else:
                hi = mid
        return lo + k

