var findKthPositive = function(arr, k) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        const missing = arr[mid] - (mid + 1);
        if (missing < k) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return lo + k;
};
